// Get data from trigger and Load Task Data
const triggerData = $('1. When Executed by Another Workflow').first().json;  // ← От Квалификатора
const taskData = $('2. Load Task Data').first().json;  // ← Из БД

// Parse agent_output
let agentOutput = taskData.agent_output;
if (typeof agentOutput === 'string') {
  try {
    agentOutput = JSON.parse(agentOutput);
  } catch (e) {
    agentOutput = {};
  }
}

// Get versions array
const versions = agentOutput?.versions || [];
const currentVersion = versions.length > 0 ? versions.length + 1 : 1;

// ✅ ИСПРАВЛЕНИЕ: Читаем из triggerData (от Квалификатора)
const userRequest = triggerData.effective_user_request ||  // ← ИЗ TRIGGER!
                    triggerData.source_data?.user_request || 
                    taskData.effective_user_request ||
                    taskData.initial_prompt || 
                    '';

console.log('[Determine Source Context] User request:', userRequest);
console.log('[Determine Source Context] triggerData.effective_user_request:', triggerData.effective_user_request);

// ✅ Extract reference data from triggerData first
const referenceTaskId = triggerData.source_data?.reference_task_id || taskData.source_data?.reference_task_id || null;
const referenceType = triggerData.source_data?.reference_type || taskData.source_data?.reference_type || null;

console.log('[Determine Source Context] Reference task ID:', referenceTaskId);
console.log('[Determine Source Context] Reference type:', referenceType);

// Determine source type
let sourceType = 'text_only';
let sourceData = {
  post_text: triggerData.post_text || '',
  user_request: userRequest,
  current_version: currentVersion,
  reference_task_id: referenceTaskId,
  reference_type: referenceType
};

// Check for reference photo
if (triggerData.reference_photo_url || taskData.reference_photo_url) {
  sourceType = 'with_reference';
  sourceData.reference_photo_url = triggerData.reference_photo_url || taskData.reference_photo_url;
  sourceData.file_id = triggerData.file_id || taskData.file_id || null;
}

// Check for previous prompt
if (versions.length > 0) {
  const lastVersion = versions[versions.length - 1];
  if (lastVersion && lastVersion.flux_prompt) {
    sourceType = 'modify_previous';
    sourceData.previous_prompt = lastVersion.flux_prompt;
    sourceData.previous_image_url = lastVersion.image_url;
    if (lastVersion.flux_params) {
      sourceData.previous_params = lastVersion.flux_params;
    }
  }
}

// Check for from_scratch flag
if (triggerData.from_scratch === true || taskData.from_scratch === true) {
  sourceType = 'from_scratch';
  delete sourceData.previous_prompt;
  delete sourceData.previous_params;
  delete sourceData.previous_image_url;
}

console.log('[Determine Source Context] Source type:', sourceType);
console.log('[Determine Source Context] Final user_request:', sourceData.user_request);

return {
  source_type: sourceType,
  source_data: sourceData,
  task_id: taskData.id,
  task_type: taskData.task_type,
  chat_id: taskData.chat_id
};

// Получаем context из предыдущей ноды
const context = $input.first().json;
const sourceData = context.source_data || {};

// Проверяем нужно ли загружать referenced task
const needsReference = Boolean(
  sourceData.reference_task_id && 
  sourceData.reference_type === 'post'
);

console.log('[Check Reference Task] needs_reference:', needsReference);

// Возвращаем весь context + флаг needs_reference
return {
  json: {
    ...context,
    needs_reference: needsReference,
    reference_task_id: sourceData.reference_task_id || null
  }
};

// Получаем context из Check Reference Task (используем $node)
const checkNode = $('4. Check Reference Task').first().json;
const context = {...checkNode};
const sourceData = {...(context.source_data || {})};

try {
  // Получаем referenced task из Supabase
  const referencedTask = $input.first().json;

  console.log('[Extract Referenced Data] Loading task:', referencedTask.id);

  // Извлекаем post_text из последней версии copywriting задачи
  const versions = referencedTask.agent_output?.versions || [];

  if (versions.length > 0) {
    // Берём последнюю версию
    const lastVersion = versions[versions.length - 1];
    sourceData.post_text = lastVersion.agent_response || '';
    console.log('[Extract Referenced Data] Loaded from version', versions.length);
  } else {
    // Fallback: если versions пустой (ручное создание или старая задача)
    console.log('[Extract Referenced Data] Warning: versions array empty, using initial_prompt');
    sourceData.post_text = referencedTask.initial_prompt || '';
  }

  // Дополнительная проверка что post_text не пустой
  if (!sourceData.post_text || sourceData.post_text.trim().length === 0) {
    console.log('[Extract Referenced Data] Error: post_text is empty after extraction');
    sourceData.post_text = `[Не удалось загрузить текст поста из задачи ${referencedTask.id}]`;
  } else {
    console.log('[Extract Referenced Data] Successfully loaded post_text, length:', sourceData.post_text.length);
  }

  sourceData.referenced_task_id = referencedTask.id;  // Для трекинга

} catch (e) {
  console.log('[Extract Referenced Data] Error:', e.message);
  sourceData.post_text = '[Ошибка загрузки referenced task]';
}

// Возвращаем обновлённый context
return {
  json: {
    ...context,
    source_data: sourceData
  }
};

// Получаем AI response
let aiResponse;
try {
  aiResponse = $('11. AI Agent (With Photo)').first().json;
} catch (e) {
  try {
    aiResponse = $('11.1. AI Agent (Text Only)').first().json;
  } catch (e2) {
    aiResponse = { text: '' };
  }
}

// ✅ Читаем source_data из Set Style Preference (не из AI Agent!)
const styleNode = $('8. Set Style Preference').first().json;

// Извлекаем flux_prompt из text
const fluxPrompt = aiResponse.text || aiResponse.output?.flux_prompt || '';

// TODO: flux_params пока пустой
const fluxParams = {};

// ✅ Берем source_data из Set Style Preference
const sourceData = styleNode.source_data || {};

return {
  task_id: styleNode.task_id,
  prompt: fluxPrompt,
  flux_prompt: fluxPrompt,
  flux_params: fluxParams,
  source_type: styleNode.source_type,
  user_request: sourceData.user_request || '',
  post_text: sourceData.post_text || '',
  current_version: sourceData.current_version || 1,
  chat_id: styleNode.chat_id
};

// Получаем данные от FLUX API
const fluxResult = $input.first().json;

// Получаем merged data
const mergedData = $('12. Merge Prompt & Params').first().json;

// Получаем task data
const taskData = $('2. Load Task Data').first().json;

// Собираем ВСЕ данные в один объект
return {
  // FLUX API данные
  flux_image_url: fluxResult.images?.[0]?.url || '',
  flux_result: fluxResult,

  // Merged data
  task_id: mergedData.task_id,
  flux_prompt: mergedData.flux_prompt,
  flux_params: mergedData.flux_params,
  user_request: mergedData.user_request,
  post_text: mergedData.post_text,
  current_version: mergedData.current_version,
  source_type: mergedData.source_type,

  // Task data
  chat_id: taskData.chat_id,
  agent_output: taskData.agent_output
};

const telegramResponse = $input.first().json.result;
const allData = $('16. Prepare All Data').first().json;

const versionData = {
  version: allData.current_version,
  timestamp: new Date().toISOString(),
  flux_prompt: allData.flux_prompt,
  flux_params: allData.flux_params,
  image_url: allData.flux_image_url,  // ✅ Сохраняем URL от FLUX
  model: 'flux-pro-v1.1-ultra',
  user_request: allData.user_request,
  source_type: allData.source_type
};

return [{
  json: {
    telegram_message_id: telegramResponse.message_id,
    telegram_chat_id: telegramResponse.chat.id,
    message_type: 'photo',
    task_id: allData.task_id,
    source_type: 'task',
    source_id: allData.task_id,
    content_data: versionData,
    created_at: new Date().toISOString()
  }
}];

const allData = $('16. Prepare All Data').first().json;

// Parse agent_output
let agentOutput = allData.agent_output;
if (typeof agentOutput === 'string') {
  try {
    agentOutput = JSON.parse(agentOutput);
  } catch (e) {
    agentOutput = {};
  }
}

// Get or initialize versions array
let versions = agentOutput?.versions || [];

// Create new version entry
const newVersion = {
  version: allData.current_version,
  timestamp: new Date().toISOString(),
  flux_prompt: allData.flux_prompt,
  flux_params: allData.flux_params,
  image_url: allData.flux_image_url,
  model: 'flux-pro-v1.1-ultra',
  user_request: allData.user_request,
  source_type: allData.source_type
};

// Add new version
versions.push(newVersion);

// ✅ ИСПРАВЛЕНИЕ: Создаем чистый agent_output БЕЗ старых полей error
const updatedAgentOutput = {
  versions: versions,
  latest_image_url: newVersion.image_url,
  latest_prompt: newVersion.flux_prompt,
  current_version: allData.current_version
};

return {
  task_id: allData.task_id,
  agent_output: updatedAgentOutput,
  status: 'completed',
  updated_at: new Date().toISOString()
};

// Get error information
const error = $input.first().json.error || {};
const errorMessage = error.message || 'Unknown error occurred';

// Get task data
const taskData = $('2. Load Task Data').first().json;

// Try to get merge node data
let mergeNode;
try {
  mergeNode = $('12. Merge Prompt & Params').first().json;
} catch (e) {
  mergeNode = {};
}

return {
  task_id: mergeNode.task_id || taskData.id,
  error_message: errorMessage,
  status: 'failed',
  updated_at: new Date().toISOString(),

  agent_output: {
    versions: taskData.agent_output?.versions || [],
    current_version: taskData.agent_output?.current_version || 1,
    error: errorMessage,
    error_timestamp: new Date().toISOString()
  },

  user_message: `❌ Не удалось создать изображение\n\nОшибка: ${errorMessage}\n\nПопробуй еще раз.`,

  chat_id: taskData.chat_id
};
